app = FastAPI(lifespan=lifespan)

security = HTTPBearer()

class TokenValidator:
    def __init__(self, redis_client: redis.Redis):
        self.redis_client = redis_client
    
    async def validate_token(self, token: str) -> Dict[str, Any]:
        token_data = await self.redis_client.get(f"token:{token}")
        
        if not token_data:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": "Bearer"},
            )
        
        try:
            token_info = json.loads(token_data)
            
            if "expires_at" in token_info:
                expires_at = datetime.fromisoformat(token_info["expires_at"])
                if datetime.utcnow() > expires_at:
                    await self.redis_client.delete(f"token:{token}")
                    raise HTTPException(
                        status_code=status.HTTP_401_UNAUTHORIZED,
                        detail="Token has expired",
                        headers={"WWW-Authenticate": "Bearer"},
                    )
            
            return token_info
        except json.JSONDecodeError:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid token format",
                headers={"WWW-Authenticate": "Bearer"},
            )

async def get_token_validator() -> TokenValidator:
    if redis_client is None:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    return TokenValidator(redis_client)

async def verify_token(
    credentials: HTTPAuthorizationCredentials = Depends(security),
    validator: TokenValidator = Depends(get_token_validator)
) -> Dict[str, Any]:
    token = credentials.credentials
    token_info = await validator.validate_token(token)
    return token_info

async def verify_token_from_header(
    authorization: Optional[str] = Header(None),
    validator: TokenValidator = Depends(get_token_validator)
) -> Dict[str, Any]:
    if not authorization:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Authorization header missing",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    parts = authorization.split()
    
    if len(parts) != 2 or parts[0].lower() != "bearer":
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid authorization header format",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    token = parts[1]
    token_info = await validator.validate_token(token)
    return token_info

