@app.post("/auth/token")
async def create_token(user_id: str, username: str, scopes: list[str] = None):
    if redis_client is None:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    
    import secrets
    token = secrets.token_urlsafe(32)
    
    from datetime import timedelta
    expires_at = datetime.utcnow() + timedelta(hours=1)
    
    token_data = {
        "user_id": user_id,
        "username": username,
        "scopes": scopes or [],
        "expires_at": expires_at.isoformat(),
        "created_at": datetime.utcnow().isoformat()
    }
    
    await redis_client.setex(
        f"token:{token}",
        3600,
        json.dumps(token_data)
    )
    
    return {
        "access_token": token,
        "token_type": "bearer",
        "expires_in": 3600
    }

@app.delete("/auth/token")
async def revoke_token(token_info: Dict[str, Any] = Depends(verify_token_from_header)):
    if redis_client is None:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    
    authorization = token_info.get("_token")
    if authorization:
        await redis_client.delete(f"token:{authorization}")
    
    return {"message": "Token revoked successfully"}

@app.get("/health")
async def health_check():
    if redis_client is None:
        return {"status": "unhealthy", "redis": "disconnected"}
    
    try:
        await redis_client.ping()
        return {"status": "healthy", "redis": "connected"}
    except Exception as e:
        return {"status": "unhealthy", "redis": "error", "error": str(e)}

class ScopeChecker:
    def __init__(self, required_scopes: list[str]):
        self.required_scopes = required_scopes
    
    async def __call__(self, token_info: Dict[str, Any] = Depends(verify_token)) -> Dict[str, Any]:
        token_scopes = set(token_info.get("scopes", []))
        required_scopes = set(self.required_scopes)
        
        if not required_scopes.issubset(token_scopes):
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"Required scopes: {', '.join(self.required_scopes)}"
            )
        
        return token_info

